class Solution {
public:
    vector<int> separateDigits(vector<int>& nums) {
        vector<int> answer;
        for (int num : nums) {
            string strNum = to_string(num);
            for (char digit : strNum) {
                answer.push_back(digit - '0');
            }
        }
        return answer;
    }
};
